const postsRows = $('Get Latest Posts').all();
const likesRows = $('Get Post Likes').all();
const commentsRows = $('Get Post Comments').all();
const messagesRows = $('Get Recent Messages').all();
const invitationsRows = $('Get Recent Invitations').all();
const outboundRows = $('Get Our Outbound Activity').all();

let text = 'LINKEDIN ACTIVITY & PERFORMANCE REPORT FOR DON JIMMY\n\n';
let refMap = {};
let refCounter = 1;

// 1. Map comments and likes to posts
const posts = {};
postsRows.forEach(row => {
  const p = row.json;
  if (!p.post_id) return;
  posts[p.post_id] = {
    content: p.post_content,
    url: p.post_url,
    published_at: p.post_published_at,
    likes_count: 0,
    comments: []
  };
});

likesRows.forEach(row => {
  const l = row.json;
  if (posts[l.post_id]) {
    posts[l.post_id].likes_count++;
  }
});

commentsRows.forEach(row => {
  const c = row.json;
  if (posts[c.post_id]) {
    posts[c.post_id].comments.push({
      author: c.comment_author,
      content: c.comment_content,
      published_at: c.comment_published_at
    });
  }
});

// 2. Format Posts & Comments Received
text += '=== LATEST PUBLISHED POSTS & INBOUND ENGAGEMENT ===\n';
if (Object.keys(posts).length === 0) {
  text += 'No posts published in the last 7 days.\n\n';
} else {
  Object.entries(posts).forEach(([pId, post]) => {
    const refId = refCounter++;
    const snippet = (post.content || '').substring(0, 40).replace(/\n/g, ' ') || 'LinkedIn Post';
    refMap[String(refId)] = { title: snippet, url: post.url || '' };

    text += `[Post #${refId}] | Likes Received: ${post.likes_count} | Published: ${post.published_at}\n`;
    text += `Content: ${post.content || 'No content'}\n`;
    if (post.comments.length > 0) {
      text += `Comments Received:\n`;
      post.comments.forEach(comment => {
        text += `  - by ${comment.author}: ${comment.content}\n`;
      });
    }
    text += '\n';
  });
}

// 3. Format Outbound Activity
text += '=== OUTBOUND ENGAGEMENT (My Likes & Comments on LinkedIn) ===\n';
if (outboundRows.length === 0 || !outboundRows[0].json.type) {
  text += 'No outbound likes or comments in the last 7 days.\n\n';
} else {
  outboundRows.forEach(row => {
    const act = row.json;
    if (act.type === 'comment') {
      text += `- Commented on post (ID: ${act.post_id}) at ${act.published_at}: "${act.content}"\n`;
    } else {
      text += `- Liked post (ID: ${act.post_id}) at ${act.published_at}\n`;
    }
  });
  text += '\n';
}

// 4. Format Messages
text += '=== DIRECT MESSAGES (Last 7 Days) ===\n';
if (messagesRows.length === 0 || !messagesRows[0].json.sender_name) {
  text += 'No new inbox messages.\n\n';
} else {
  messagesRows.forEach(row => {
    const msg = row.json;
    text += `From: ${msg.sender_name} | To: ${msg.recipient_name} | Sent: ${msg.sent_at}\n`;
    text += `Message: ${msg.content || 'No content'}\n\n`;
  });
}

// 5. Format Connection Requests
text += '=== CONNECTION INVITATIONS (Last 7 Days) ===\n';
if (invitationsRows.length === 0 || !invitationsRows[0].json.from_name) {
  text += 'No new connection requests.\n\n';
} else {
  invitationsRows.forEach(row => {
    const invite = row.json;
    text += `Direction: ${invite.direction} | From: ${invite.from_name} | To: ${invite.to_name} | Sent: ${invite.sent_at}\n`;
    if (invite.message) {
      text += `Personal Note: ${invite.message}\n`;
    }
    text += '\n';
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

return [{ json: { text, ref_map: refMap, giusy_persona: persona } }];

const raw = $input.first().json.content || $input.first().json.response || '';
const refMap = $('Format Data for LLM').first().json.ref_map || {};

let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    const cleanedStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(cleanedStr);
  } catch (err) {
    return [{ json: { response: raw } }];
  }
}

const greeting = parsed.greeting || '';
const signoff = parsed.signoff || '';
const performanceCritique = Array.isArray(parsed.performance_critique) ? parsed.performance_critique : [];
const outboundCritique = parsed.outbound_critique || '';
const inboxInsights = Array.isArray(parsed.inbox_insights) ? parsed.inbox_insights : [];
const communityActions = Array.isArray(parsed.community_engagement_actions) ? parsed.community_engagement_actions : [];
const strategicRecommendations = Array.isArray(parsed.strategic_recommendations) ? parsed.strategic_recommendations : [];

let msg = '';
if (greeting) msg += `${greeting}\n\n`;
msg += '📊 *LinkedIn Content Performance & Resonance Critique* 📊\n\n';

if (performanceCritique.length > 0) {
  msg += '*Inbound Post-by-Post Feedback*:\n';
  performanceCritique.forEach(c => {
    const ref = refMap[String(c.post_id)];
    const linkStr = ref && ref.url ? `<${ref.url}|${ref.title}...>` : `Post #${c.post_id}`;
    msg += `• *${linkStr}* | Resonance: *${c.resonance_score || 'N/A'}*\n`;
    msg += `  - *What worked*: ${c.positives || 'None'}\n`;
    msg += `  - *Critique*: ${c.critique || 'None'}\n`;
  });
  msg += '\n';
}

if (outboundCritique) {
  msg += '*Outbound Activity Critique*:\n';
  msg += `• ${outboundCritique}\n\n`;
}

if (inboxInsights.length > 0) {
  msg += '*Inbox & Leads Analysis*:\n';
  inboxInsights.forEach(insight => {
    msg += `• ${insight}\n`;
  });
  msg += '\n';
}

if (communityActions.length > 0) {
  msg += '*Community & Lead Actions*:\n';
  communityActions.forEach(action => {
    msg += `• *${action.type || 'Action'}* with *${action.target || 'Community'}*:\n`;
    msg += `  > "${action.actionable_reply}"\n`;
  });
  msg += '\n';
}

if (strategicRecommendations.length > 0) {
  msg += '*Strategic Writing Directives*:\n';
  strategicRecommendations.forEach(rec => {
    msg += `• ${rec}\n`;
  });
  msg += '\n';
}

if (signoff) msg += `${signoff}`;

return [{ json: { response: msg.trim() } }];
